SELECT A.SEQ, A.RESUME_SEQ, A.PERSON_ID, A.EMPID, A.LOCAL_NAME, A.DEPTNO, GET_DEPT_NAME(A.DEPTNO, #{lang, jdbcType=VARCHAR}) DEPTNAME, A.POST_GRADE_NO, A.POST_GRADE_NAME, A.MAIN_BUSINESS, GET_GLOBAL_NAME(A.MAIN_BUSINESS, #{lang, jdbcType=VARCHAR}) MAIN_BUSINESS_NAME, A.OBJECT_TYPE, A.OBJECT_TYPE_NAME, TO_CHAR(A.DATE_STARTED, 'DD/MM/YYYY') DATE_STARTED, A.LIST_TYPE_NAME, A.EVS_GROUP_NAME, A.EVS_OCC_GROUP, A.EVS_OCC_GROUP_NAME, TO_CHAR(A.UPDATE_DATE, 'DD/MM/YYYY HH24:MI') UPDATE_DATE, GET_UPDATED_INFO(A.UPDATED_BY) || ' ' || A.UPDATED_IP UPDATED_BY, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 0, 'LOCAL_NAME') LOCAL_NAME0, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'LOCAL_NAME') LOCAL_NAME1, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 2, 'LOCAL_NAME') LOCAL_NAME2, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 3, 'LOCAL_NAME') LOCAL_NAME3, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 4, 'LOCAL_NAME') LOCAL_NAME4, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 0, 'POST_GRADE_NAME') POST_GRADE_NAME0, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'POST_GRADE_NAME') POST_GRADE_NAME1, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 2, 'POST_GRADE_NAME') POST_GRADE_NAME2, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 3, 'POST_GRADE_NAME') POST_GRADE_NAME3, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 4, 'POST_GRADE_NAME') POST_GRADE_NAME4, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'AFFIRMOR_ID') PERSON_ID1, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 2, 'AFFIRMOR_ID') PERSON_ID2, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 3, 'AFFIRMOR_ID') PERSON_ID3, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 4, 'AFFIRMOR_ID') PERSON_ID4 FROM EVS_OBJECT A WHERE A.RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}
AND A.DEPTNO IN
#{dno, jdbcType=VARCHAR}
AND (PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'LOCAL_NAME') LIKE '%' || #{affirmorKeyword, jdbcType=VARCHAR} || '%' OR PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 2, 'LOCAL_NAME') LIKE '%' || #{affirmorKeyword, jdbcType=VARCHAR} || '%' OR PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 3, 'LOCAL_NAME') LIKE '%' || #{affirmorKeyword, jdbcType=VARCHAR} || '%' OR PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 4, 'LOCAL_NAME') LIKE '%' || #{affirmorKeyword, jdbcType=VARCHAR} || '%')
ORDER BY A.PERSON_ID ASC

