  FROM EVS_OBJECT
 WHERE RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}
   AND PERSON_ID  = #{personId,  jdbcType=VARCHAR}
 ORDER BY CREATE_DATE DESC
