EVS_OCC_GROUP = GET_CODE_NO(#{evsOccGroupName, jdbcType=VARCHAR}, #{resumeSeq, jdbcType=VARCHAR}, 'FAMILY', 'EVS_PARAM'), EVS_OCC_GROUP_NAME = #{evsOccGroupName, jdbcType=VARCHAR},
UPDATE_DATE = SYSDATE, UPDATED_BY = #{adminID, jdbcType=VARCHAR}, UPDATED_IP = #{adminIP, jdbcType=VARCHAR}
